/**
 * Tests for the DomainValidator.
 *
 * @version $Revision$ $Date$
 */
public class DomainValidatorTest extends TestCase {

    private DomainValidator validator;

    public void setUp() {
        validator = DomainValidator.getInstance();
    }

    public void testIDN() {
